command_failures.command:
/bin/zsh -lc "node --input-type=module - <<'EOF'
import puppeteer from 'puppeteer';
import fs from 'node:fs/promises';

const url = 'http://127.0.0.1:8566/sessions/3671e0d9-82a2-41bf-8195-b35b5d950ec2?stage=audio';
await fs.mkdir('/Users/kevin/code/storyteller/.artifacts/webapp-qa', { recursive: true });

const browser = await puppeteer.launch({ headless: 'new' });

for (const [name, viewport] of Object.entries({
  desktop: { width: 1440, height: 1400 },
  mobile: { width: 430, height: 1200 },
})) {
  const page = await browser.newPage();
  await page.setViewport(viewport);
  await page.goto(url, { waitUntil: 'networkidle2' });
  await page.waitForFunction(() => document.body.innerText.includes('Segment status'));
  await page.waitForFunction(() => document.body.innerText.includes('Compiled narration'));
  const text = await page.evaluate(() => document.body.innerText);
  if ("'!text.includes('"'Generating now')) {
    throw new Error("'`Missing segment activity state on ${name}`);
  }
  if (!text.includes('"'Checkpoint preview clip')) {
    throw new Error("'`Missing preview distinction on ${name}`);
  }
  const path = `/Users/kevin/code/storyteller/.artifacts/webapp-qa/prompt-76-audio-stage-${name}.png`;
  await page.screenshot({ path, fullPage: false });
  console.log(`${name}:${path}`);
  await page.close();
}

await browser.close();
EOF'
